import base64

from nwos import SUPERUSER_ID, api, tools


OLD_DEFAULT_FAVICON = (
    b""
)


def migrate(cr, version):
    env = api.Environment(cr, SUPERUSER_ID, {})
    with tools.file_open("web/static/img/favicon.ico", "rb") as favicon:
        new_default_favicon = base64.b64encode(favicon.read())

    old_default_favicon = OLD_DEFAULT_FAVICON.decode()
    websites = env["website"].search([])
    for website in websites:
        if website.favicon in (OLD_DEFAULT_FAVICON, old_default_favicon):
            website.favicon = new_default_favicon
